const quotePremium = (items: Array<{ type: string }>): number => {
  const basePrice = items.reduce((sum, item) => sum + BASE_PRICE_BY_TYPE[item.type], 0);
  const firstQuoteSurcharge = basePrice * FIRST_QUOTE_SURCHARGE_RATE;
  return basePrice + firstQuoteSurcharge + PROCESSING_FEE;
};
